	private final Grammar grammar;
	
	private final TerminalsGrammarAccess gaTerminals;

	@Inject
	public MyDslGrammarAccess(GrammarProvider grammarProvider,
			TerminalsGrammarAccess gaTerminals) {
		this.grammar = internalFindGrammar(grammarProvider);
		this.gaTerminals = gaTerminals;
		this.pModel = new ModelElements();
		this.pStep = new StepElements();
		this.pEString = new EStringElements();
		this.pEBoolean = new EBooleanElements();
		this.pTable = new TableElements();
		this.pColumn = new ColumnElements();
		this.eDataType = new DataTypeElements();
		this.pSave = new SaveElements();
		this.pGroup = new GroupElements();
		this.pSort = new SortElements();
		this.pAppendRows = new AppendRowsElements();
		this.pFilter = new FilterElements();
		this.pGenericStep = new GenericStepElements();
		this.pJoin = new JoinElements();
		this.pImport = new ImportElements();
		this.pLookup = new LookupElements();
		this.pRemoveDuplicates = new RemoveDuplicatesElements();
		this.pConcat = new ConcatElements();
		this.pSplit = new SplitElements();
		this.pExtract = new ExtractElements();
		this.pTableToSave = new TableToSaveElements();
		this.eGroupOperationType = new GroupOperationTypeElements();
		this.eOrderType = new OrderTypeElements();
		this.pAssociation = new AssociationElements();
		this.eFilterOperatorType = new FilterOperatorTypeElements();
		this.eJoinType = new JoinTypeElements();
		this.pTableToImport = new TableToImportElements();
		this.eLookupOperationType = new LookupOperationTypeElements();
		this.pEIntegerObject = new EIntegerObjectElements();
		this.pEBooleanObject = new EBooleanObjectElements();
	}
	
	protected Grammar internalFindGrammar(GrammarProvider grammarProvider) {
		Grammar grammar = grammarProvider.getGrammar(this);
		while (grammar != null) {
			if ("org.xtext.example.mydsl.MyDsl".equals(grammar.getName())) {
				return grammar;
			}
			List<Grammar> grammars = grammar.getUsedGrammars();
			if (!grammars.isEmpty()) {
				grammar = grammars.iterator().next();
			} else {
				return null;
			}
		}
		return grammar;
	}
	
	@Override
	public Grammar getGrammar() {
		return grammar;
	}
	
	
	public TerminalsGrammarAccess getTerminalsGrammarAccess() {
		return gaTerminals;
	}

	
	//Model returns Model:
	//    name=EString
	//        'logs:' logs=EBooleanObject
	//        'tables:' tables+=Table (tables+=Table)*
